from pydantic import BaseModel, Field

app = FastAPI(title="Multi-Tenant ML Model Serving Platform")

# In-memory storage for models and tenant info
model_registry: Dict[str, Dict[str, Any]] = {}
tenant_models: Dict[str, list] = {}

UPLOAD_DIR = tempfile.mkdtemp(prefix="ml_models_")
MAX_FILE_SIZE = 100 * 1024 * 1024  # 100MB
ALLOWED_PICKLE_PROTOCOLS = {0, 1, 2, 3, 4, 5}


class InferenceRequest(BaseModel):
    model_id: str
    input_data: Any = Field(..., description="Input data for model inference")


class ModelInfo(BaseModel):
    model_id: str
    tenant_id: str
    filename: str
    uploaded_at: str
    file_size: int
    file_hash: str
    status: str


class SafeUnpickler(pickle.Unpickler):
    """
    Restricted unpickler that blocks dangerous modules and builtins.
    This provides a layer of defense against arbitrary code execution
    via malicious pickle files.
    """

    BLOCKED_MODULES = {
        "os",
        "subprocess",
        "sys",
        "builtins",
        "shutil",
        "importlib",
        "ctypes",
        "socket",
        "http",
        "urllib",
        "requests",
        "webbrowser",
        "code",
        "codeop",
        "compile",
        "compileall",
        "py_compile",
        "zipimport",
        "pkgutil",
        "pdb",
        "profile",
        "trace",
        "signal",
        "multiprocessing",
        "threading",
        "_thread",
        "concurrent",
        "asyncio",
        "posix",
        "nt",
        "posixpath",
        "ntpath",
        "io",
        "tempfile",
        "glob",
        "fnmatch",
        "pathlib",
        "fileinput",
        "tokenize",
        "runpy",
        "pty",
        "commands",
        "popen2",
        "resource",
        "grp",
        "pwd",
    }

    BLOCKED_NAMES = {
        "exec",
        "eval",
        "execfile",
        "compile",
        "__import__",
        "open",
        "file",
        "input",
        "raw_input",
        "reload",
        "getattr",
        "setattr",
        "delattr",
        "globals",
        "locals",
        "vars",
        "dir",
        "type",
        "super",
        "classmethod",
        "staticmethod",
        "property",
        "system",
        "popen",
        "fdopen",
        "tmpfile",
        "fchmod",
        "fchown",
        "rmdir",
        "removedirs",
        "rename",
        "renames",
        "unlink",
        "remove",
        "walk",
        "listdir",
        "scandir",
        "makedirs",
        "mkdir",
        "link",
        "symlink",
        "kill",
        "abort",
    }

    ALLOWED_MODULES = {
        "sklearn",
        "sklearn.linear_model",
        "sklearn.ensemble",
        "sklearn.tree",
        "sklearn.svm",
        "sklearn.neighbors",
        "sklearn.naive_bayes",
        "sklearn.neural_network",
        "sklearn.preprocessing",
        "sklearn.pipeline",
        "sklearn.base",
        "sklearn.utils",
        "numpy",
        "numpy.core",
        "numpy.core.multiarray",
        "numpy.core._multiarray_umath",
        "numpy.dtype",
        "scipy",
        "scipy.sparse",
        "xgboost",
        "lightgbm",
        "catboost",
        "copy_reg",
        "copyreg",
        "_codecs",
        "codecs",
        "collections",
        "collections.abc",
        "functools",
        "operator",
        "itertools",
        "_collections_abc",
    }

    def find_class(self, module: str, name: str) -> Any:
        # Check if the module or any parent module is blocked
        module_parts = module.split(".")
        for i in range(len(module_parts)):
            partial_module = ".".join(module_parts[: i + 1])
            if partial_module in self.BLOCKED_MODULES:
                raise pickle.UnpicklingError(
                    f"Blocked attempt to load '{name}' from restricted module '{module}'"
                )

        # Check if the name itself is blocked
        if name in self.BLOCKED_NAMES:
            raise pickle.UnpicklingError(
                f"Blocked attempt to load restricted callable '{name}'"
            )

        # Check against allowlist - module must start with an allowed prefix
        module_allowed = False
        for allowed in self.ALLOWED_MODULES:
            if module == allowed or module.startswith(allowed + "."):
                module_allowed = True
                break

        if not module_allowed:
            raise pickle.UnpicklingError(
                f"Module '{module}' is not in the allowlist. "
                f"Contact platform admin to add support for this module."
            )

        return super().find_class(module, name)


def safe_pickle_load(file_bytes: bytes) -> Any:
    """
    Safely load a pickle file using the restricted unpickler.
    """
    buffer = io.BytesIO(file_bytes)
    try:
        unpickler = SafeUnpickler(buffer)
        model = unpickler.load()
        return model
    except pickle.UnpicklingError:
        raise
    except Exception as e:
        raise pickle.UnpicklingError(f"Failed to deserialize model: {str(e)}")


def validate_pickle_header(file_bytes: bytes) -> bool:
    """
    Basic validation of pickle file structure.
    """
    if len(file_bytes) < 2:
        return False

    # Check for valid pickle opcodes at the start
    first_byte = file_bytes[0]
    valid_starts = {
        0x80,  # PROTO opcode (protocol 2+)
        0x28,  # MARK
        0x7D,  # EMPTY_DICT
        0x5D,  # EMPTY_LIST
        0x29,  # EMPTY_TUPLE
        0x4E,  # NONE
        0x89,  # NEWOBJ_EX
        0x8C,  # SHORT_BINUNICODE
        0x63,  # GLOBAL
    }

    if first_byte not in valid_starts:
        # Could also start with other valid opcodes, but these are most common
        pass

    # Check that STOP opcode exists
    if 0x2E not in file_bytes:  # '.' STOP opcode
        return False

    return True


def compute_file_hash(file_bytes: bytes) -> str:
    """Compute SHA-256 hash of file contents."""
    return hashlib.sha256(file_bytes).hexdigest()


def validate_tenant_id(tenant_id: str) -> str:
    """Validate and sanitize tenant ID."""
    if not tenant_id or not tenant_id.strip():
        raise HTTPException(status_code=400, detail="Tenant ID is required")

    sanitized = tenant_id.strip()
    if len(sanitized) > 128:
        raise HTTPException(
            status_code=400, detail="Tenant ID too long (max 128 chars)"
        )

    # Only allow alphanumeric, hyphens, underscores
    if not all(c.isalnum() or c in "-_" for c in sanitized):
        raise HTTPException(
            status_code=400,
            detail="Tenant ID must contain only alphanumeric characters, hyphens, and underscores",
        )

    return sanitized


async def get_tenant_id(x_tenant_id: str = Header(..., alias="X-Tenant-ID")) -> str:
    """Extract and validate tenant ID from request header."""
    return validate_tenant_id(x_tenant_id)


@app.post("/models/upload", response_model=ModelInfo)
async def upload_model(
    file: UploadFile = File(...),
    description: Optional[str] = Form(None),
    tenant_id: str = Depends(get_tenant_id),
):
    """
    Upload a serialized model file for a specific tenant.
    The model is validated using a restricted unpickler before being accepted.
    """
    # Validate file extension
    if not file.filename:
        raise HTTPException(status_code=400, detail="Filename is required")

    allowed_extensions = {".pkl", ".pickle", ".joblib", ".model"}
    file_ext = os.path.splitext(file.filename)[1].lower()
    if file_ext not in allowed_extensions:
        raise HTTPException(
            status_code=400,
            detail=f"File extension '{file_ext}' not allowed. Allowed: {allowed_extensions}",
        )

    # Read file with size limit
    file_bytes = await file.read()
    if len(file_bytes) > MAX_FILE_SIZE:
        raise HTTPException(
            status_code=413,
            detail=f"File too large. Maximum size is {MAX_FILE_SIZE / (1024*1024):.0f}MB",
        )

    if len(file_bytes) == 0:
        raise HTTPException(status_code=400, detail="Empty file uploaded")

    # Validate pickle header
    if not validate_pickle_header(file_bytes):
        raise HTTPException(
            status_code=400, detail="File does not appear to be a valid pickle file"
        )

    # Compute file hash for integrity
    file_hash = compute_file_hash(file_bytes)

    # Check for duplicate uploads for this tenant
    if tenant_id in tenant_models:
        for existing_model_id in tenant_models[tenant_id]:
            if model_registry.get(existing_model_id, {}).get("file_hash") == file_hash:
                raise HTTPException(
                    status_code=409,
                    detail=f"Duplicate model detected. Existing model ID: {existing_model_id}",
                )

    # Attempt to load model with safe unpickler to validate it
    try:
        model = safe_pickle_load(file_bytes)
    except pickle.UnpicklingError as e:
        raise HTTPException(
            status_code=400,
            detail=f"Model validation failed - potentially unsafe content detected: {str(e)}",
        )
    except Exception as e:
        raise HTTPException(
            status_code=400,
            detail=f"Failed to load model file: {str(e)}",
        )

    # Validate the model has a predict method (basic ML model interface check)
    if not hasattr(model, "predict") and not hasattr(model, "transform"):
        raise HTTPException(
            status_code=400,
            detail="Uploaded model must have a 'predict' or 'transform' method",
        )

    # Generate model ID and store
    model_id = f"{tenant_id}_{uuid.uuid4().hex[:12]}"

    # Save file to disk
    tenant_dir = os.path.join(UPLOAD_DIR, tenant_id)
    os.makedirs(tenant_dir, exist_ok=True)
    file_path = os.path.join(tenant_dir, f"{model_id}{file_ext}")

    with open(file_path, "wb") as f:
        f.write(file_bytes)

    # Register model
    model_info = {
        "model_id": model_id,
        "tenant_id": tenant_id,
        "filename": file.filename,
        "file_path": file_path,
        "file_hash": file_hash,
        "file_size": len(file_bytes),
        "uploaded_at": datetime.utcnow().isoformat(),
        "description": description,
        "status": "active",
        "model_object": model,  # Keep in memory for fast inference
    }

    model_registry[model_id] = model_info

    if tenant_id not in tenant_models:
        tenant_models[tenant_id] = []
    tenant_models[tenant_id].append(model_id)

    return ModelInfo(
        model_id=model_id,
        tenant_id=tenant_id,
        filename=file.filename,
        uploaded_at=model_info["uploaded_at"],
        file_size=len(file_bytes),
        file_hash=file_hash,
        status="active",
    )


@app.post("/models/inference")
async def run_inference(
    request: InferenceRequest,
    tenant_id: str = Depends(get_tenant_id),
):
    """
    Run inference using an uploaded model.
    Tenant isolation is enforced - tenants can only access their own models.
    """
    model_id = request.model_id

    # Check model exists
    if model_id not in model_registry:
        raise HTTPException(status_code=404, detail=f"Model '{model_id}' not found")

    model_info = model_registry[model_id]

    # Tenant isolation check
    if model_info["tenant_id"] != tenant_id:
        raise HTTPException(
            status_code=403,
            detail="Access denied. You can only access your own models.",
        )

    if model_info["status"] != "active":
        raise HTTPException(
            status_code=400,
            detail=f"Model is not active. Current status: {model_info['status']}",
        )

    model = model_info.get("model_object")

    # If model not in memory, reload from disk
    if model is None:
        try:
            with open(model_info["file_path"], "rb") as f:
                file_bytes = f.read()
            model = safe_pickle_load(file_bytes)
            model_info["model_object"] = model
        except Exception as e:
            raise HTTPException(
                status_code=500, detail=f"Failed to load model from disk: {str(e)}"
            )

    # Prepare input data
    try:
        input_data = request.input_data
        if isinstance(input_data, list):
            input_array = np.array(input_data)
            if input_array.ndim == 1:
                input_array = input_array.reshape(1, -1)
        elif isinstance(input_data, dict):
            # Handle dict input (e.g., feature name -> value)
            input_array = np.array([list(input_data.values())])
        else:
            raise ValueError(
                "Input data must be a list (or list of lists) or a dictionary"
            )
    except ValueError as e:
        raise HTTPException(status_code=400, detail=f"Invalid input data: {str(e)}")
    except Exception as e:
        raise HTTPException(
            status_code=400, detail=f"Failed to process input data: {str(e)}"
        )

    # Run inference
    try:
        if hasattr(model, "predict"):
            predictions = model.predict(input_array)
        elif hasattr(model, "transform"):
            predictions = model.transform(input_array)
        else:
            raise HTTPException(
                status_code=500,
                detail="Model does not support predict or transform operations",
            )

        # Convert numpy types to native Python types for JSON serialization
        if isinstance(predictions, np.ndarray):
            predictions = predictions.tolist()

        result = {
            "model_id": model_id,
            "predictions": predictions,
            "input_shape": list(input_array.shape),
            "timestamp": datetime.utcnow().isoformat(),
        }

        # Include probabilities if available
        if hasattr(model, "predict_proba"):
            try:
                probabilities = model.predict_proba(input_array)
                if isinstance(probabilities, np.ndarray):
                    probabilities = probabilities.tolist()
                result["probabilities"] = probabilities
            except Exception:
                pass  # Not all models support predict_proba for all inputs

        return result

    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(
            status_code=500, detail=f"Inference failed: {str(e)}"
        )


@app.get("/models", response_model=list[ModelInfo])
async def list_models(tenant_id: str = Depends(get_tenant_id)):
    """List all models for the authenticated tenant."""
    if tenant_id not in tenant_models:
        return []

    models = []
    for model_id in tenant_models[tenant_id]:
        info = model_registry[model_id]
        models.append(
            ModelInfo(
                model_id=info["model_id"],
                tenant_id=info["tenant_id"],
                filename=info["filename"],
                uploaded_at=info["uploaded_at"],
                file_size=info["file_size"],
                file_hash=info["file_hash"],
                status=info["status"],
            )
        )

    return models


@app.get("/models/{model_id}", response_model=ModelInfo)
async def get_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Get details of a specific model."""
    if model_id not in model_registry:
        raise HTTPException(status_code=404, detail=f"Model '{model_id}' not found")

    info = model_registry[model_id]

    if info["tenant_id"] != tenant_id:
        raise HTTPException(
            status_code=403,
            detail="Access denied. You can only access your own models.",
        )

    return ModelInfo(
        model_id=info["model_id"],
        tenant_id=info["tenant_id"],
        filename=info["filename"],
        uploaded_at=info["uploaded_at"],
        file_size=info["file_size"],
        file_hash=info["file_hash"],
        status=info["status"],
    )


@app.delete("/models/{model_id}")
async def delete_model(model_id: str, tenant_id: str = Depends(get_tenant_id)):
    """Delete a model (soft delete - marks as inactive)."""
    if model_id not in model_registry:
        raise HTTPException(status_code=404, detail=f"Model '{model_id}' not found")

    info = model_registry[model_id]

    if info["tenant_id"] != tenant_id:
        raise HTTPException(
            status_code=403,
            detail="Access denied. You can only delete your own models.",
        )

    # Soft delete
    info["status"] = "deleted"
    info["model_object"] = None  # Free memory

    # Remove file from disk
    try:
        if os.path.exists(info["file_path"]):
            os.remove(info["file_path"])
    except OSError:
        pass

    return {"message": f"Model '{model_id}' has been deleted", "model_id": model_id}


@app.get("/health")
async def health_check():
    """Health check endpoint."""
    return {
        "status": "healthy",
        "total_models": len(model_registry),
        "total_tenants": len(tenant_models),
        "timestamp": datetime.utcnow().isoformat(),
    }


@app.on_event("shutdown")
async def cleanup():
    """Clean up temporary files on shutdown."""
    try:
        shutil.rmtree(UPLOAD_DIR, ignore_errors=True)
    except Exception:
        pass


if __name__ == "__main__":
    import uvicorn

    uvicorn.run(app, host="0.0.0.0", port=8000)